// src/components/ParticlesBg.jsx
import { useEffect, useRef } from 'react';

export default function ParticlesBg() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let animId;

    let width = canvas.offsetWidth;
    let height = canvas.offsetHeight;

    const resize = () => {
      width = canvas.parentElement.offsetWidth;
      height = canvas.parentElement.offsetHeight;
      canvas.width = width;
      canvas.height = height;
    };
    resize();

    const ro = new ResizeObserver(resize);
    if (canvas.parentElement) ro.observe(canvas.parentElement);

    // Ratón con físicas magnéticas
    let mouse = { x: null, y: null, active: false, radius: 220 };

    const onMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      mouse.x = e.clientX - rect.left;
      mouse.y = e.clientY - rect.top;
      mouse.active = true;
    };
    
    const onLeave = () => {
      mouse.active = false;
    };

    if (canvas.parentElement) {
      canvas.parentElement.addEventListener('mousemove', onMove);
      canvas.parentElement.addEventListener('mouseleave', onLeave);
    }

    // Generamos una red densa de partículas cuánticas (200 para crear líneas fluidas)
    const PARTICLE_COUNT = 180;
    const particles = Array.from({ length: PARTICLE_COUNT }, () => {
      const angle = Math.random() * Math.PI * 2;
      const speed = Math.random() * 0.8 + 0.2;
      return {
        x: Math.random() * width,
        y: Math.random() * height,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        r: Math.random() * 1.5 + 0.5,
        alpha: Math.random() * 0.4 + 0.2,
        phase: Math.random() * 100, // Fase única para aleatoriedad orgánica
        speedPhase: Math.random() * 0.02 + 0.005,
        colorAngle: Math.random() * 20 // Pequeña variación de tono rojo/coral
      };
    });

    const draw = () => {
      // TRUCO MÁGICO: En vez de clearRect, pintamos un fondo casi transparente.
      // Esto crea el efecto de estela/fuego líquido de los hilos de luz.
      ctx.fillStyle = 'rgba(10, 10, 12, 0.06)'; 
      ctx.fillRect(0, 0, width, height);

      particles.forEach(p => {
        p.phase += p.speedPhase;

        // Movimiento base de flujo caótico sutil (Física de fluidos)
        let ax = Math.sin(p.phase + p.y * 0.005) * 0.12;
        let ay = Math.cos(p.phase + p.x * 0.005) * 0.12;

        // Si el ratón está activo, aplicamos la fuerza de VÓRTICE ORBITAL
        if (mouse.active && mouse.x !== null && mouse.y !== null) {
          const dx = mouse.x - p.x;
          const dy = mouse.y - p.y;
          const dist = Math.sqrt(dx * dx + dy * dy);

          if (dist < mouse.radius) {
            // Fuerza proporcional a la cercanía
            const force = (mouse.radius - dist) / mouse.radius;
            
            // Vector de atracción hacia el centro
            const pullX = (dx / dist) * force * 0.4;
            const pullY = (dy / dist) * force * 0.4;

            // Vector tangencial (fuerza de giro / torbellino líquido)
            const tangentX = (-dy / dist) * force * 1.8;
            const tangentY = (dx / dist) * force * 1.8;

            ax += pullX + tangentX;
            ay += pullY + tangentY;
          }
        }

        // Aplicamos aceleraciones a las velocidades
        p.vx += ax;
        p.vy += ay;

        // Fricción para que las partículas no aceleren al infinito y se mantengan fluidas
        p.vx *= 0.96;
        p.vy *= 0.96;

        // Actualizar posiciones
        p.x += p.vx;
        p.y += p.vy;

        // Teletransporte infinito suave por los bordes para mantener el flujo constante
        if (p.x < -20) p.x = width + 20;
        if (p.x > width + 20) p.x = -20;
        if (p.y < -20) p.y = height + 20;
        if (p.y > width + 20) p.y = -20;

        // Renderizar la partícula con destello neón dinámico
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);

        // Si la partícula está atrapada en el vórtice del ratón, brilla intensamente en rojo puro
        let finalAlpha = p.alpha;
        let finalColor = `rgba(232, 58, 58, ${finalAlpha})`;

        if (mouse.active && mouse.x !== null && mouse.y !== null) {
          const dx = mouse.x - p.x;
          const dy = mouse.y - p.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < mouse.radius) {
            const factor = (mouse.radius - dist) / mouse.radius;
            finalAlpha = p.alpha + factor * 0.6;
            // Variación sutil hacia tonos naranjas/fuego cuando se sobreestimula con el ratón
            finalColor = `rgba(${232 + Math.floor(factor * 23)}, ${58 + Math.floor(factor * 40)}, 58, ${finalAlpha})`;
          }
        }

        ctx.fillStyle = finalColor;
        ctx.fill();
      });

      animId = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      cancelAnimationFrame(animId);
      ro.disconnect();
      if (canvas.parentElement) {
        canvas.parentElement.removeEventListener('mousemove', onMove);
        canvas.parentElement.removeEventListener('mouseleave', onLeave);
      }
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: 'absolute',
        inset: 0,
        width: '100%',
        height: '100%',
        zIndex: 0,
        pointerEvents: 'none', /* Crucial: no interfiere con tus clicks o hovers en las tarjetas */
      }}
    />
  );
}
